class UpdateUserProfile(Mutation):
    """Mutation for updating user profiles with proper authorization checks."""

    class Arguments:
        username = String(description="New username")
        email = String(description="New email address")
        bio = String(description="New bio/description")
        role = RoleEnum(description="User role (admin only)")
        is_admin = Boolean(description="Admin status (admin only)")
        credits = Int(description="User credits (admin only)")
        subscription_tier = SubscriptionTierEnum(description="Subscription tier (admin only)")

    user = Field(UserType)
    success = Boolean(required=True)
    message = String(required=True)

    @staticmethod
    def mutate(root, info, **kwargs):
        # Get authenticated user from context
        current_user = info.context.get("current_user") if isinstance(info.context, dict) else None

        if not current_user:
            return UpdateUserProfile(user=None, success=False, message="Authentication required.")

        user_id = current_user.get("id")
        if user_id not in USERS_DB:
            return UpdateUserProfile(user=None, success=False, message="User not found.")

        user_data = USERS_DB[user_id]
        is_current_user_admin = user_data.get("is_admin", False)

        # Define which fields require admin privileges
        SELF_EDITABLE_FIELDS = {"username", "email", "bio"}
        ADMIN_ONLY_FIELDS = {"role", "is_admin", "credits", "subscription_tier"}

        # Filter out None values (fields not provided)
        updates = {k: v for k, v in kwargs.items() if v is not None}

        if not updates:
            return UpdateUserProfile(
                user=None, success=False, message="No fields provided for update."
            )

        # Check for admin-only field access
        attempted_admin_fields = set(updates.keys()) & ADMIN_ONLY_FIELDS
        if attempted_admin_fields and not is_current_user_admin:
            return UpdateUserProfile(
                user=None,
                success=False,
                message=f"Permission denied. Only admins can modify: {', '.join(attempted_admin_fields)}",
            )

        # Check for unknown fields
        allowed_fields = SELF_EDITABLE_FIELDS | ADMIN_ONLY_FIELDS
        unknown_fields = set(updates.keys()) - allowed_fields
        if unknown_fields:
            return UpdateUserProfile(
                user=None,
                success=False,
                message=f"Unknown fields: {', '.join(unknown_fields)}",
            )

        # Validate specific fields
        if "username" in updates:
            new_username = updates["username"].strip()
            if not new_username or len(new_username) < 3:
                return UpdateUserProfile(
                    user=None, success=False, message="Username must be at least 3 characters."
                )
            # Check uniqueness
            for uid, udata in USERS_DB.items():
                if uid != user_id and udata["username"] == new_username:
                    return UpdateUserProfile(
                        user=None, success=False, message="Username already taken."
                    )
            updates["username"] = new_username

        if "email" in updates:
            new_email = updates["email"].strip()
            if not new_email or "@" not in new_email:
                return UpdateUserProfile(
                    user=None, success=False, message="Invalid email address."
                )
            # Check uniqueness
            for uid, udata in USERS_DB.items():
                if uid != user_id and udata["email"] == new_email:
                    return UpdateUserProfile(
                        user=None, success=False, message="Email already in use."
                    )
            updates["email"] = new_email

        if "bio" in updates:
            if len(updates["bio"]) > 500:
                return UpdateUserProfile(
                    user=None, success=False, message="Bio must be 500 characters or less."
                )

        if "credits" in updates:
            if updates["credits"] < 0:
                return UpdateUserProfile(
                    user=None, success=False, message="Credits cannot be negative."
                )

        # Convert enum values to their string values
        if "role" in updates:
            updates["role"] = updates["role"].value if hasattr(updates["role"], "value") else updates["role"]

        if "subscription_tier" in updates:
            updates["subscription_tier"] = (
                updates["subscription_tier"].value
                if hasattr(updates["subscription_tier"], "value")
                else updates["subscription_tier"]
            )

        # Prevent non-admin from escalating own privileges
        if not is_current_user_admin:
            if "is_admin" in updates and updates["is_admin"]:
                return UpdateUserProfile(
                    user=None, success=False, message="Cannot escalate own privileges."
                )

        # Apply updates
        for field, value in updates.items():
            USERS_DB[user_id][field] = value

        updated_user = USERS_DB[user_id]
        user_obj = UserType(
            id=updated_user["id"],
            username=updated_user["username"],
            email=updated_user["email"],
            bio=updated_user["bio"],
            role=updated_user["role"],
            is_admin=updated_user["is_admin"],
            credits=updated_user["credits"],
            subscription_tier=updated_user["subscription_tier"],
        )

        return UpdateUserProfile(
            user=user_obj,
            success=True,
            message=f"Profile updated successfully. Fields modified: {', '.join(updates.keys())}",
        )


class Query(ObjectType):
    me = Field(UserType, description="Get the currently authenticated user's profile")
    user = Field(UserType, id=String(required=True), description="Get a user by ID (admin only)")
    all_users = graphene.List(UserType, description="List all users (admin only)")

    @staticmethod
    def resolve_me(root, info):
        current_user = info.context.get("current_user") if isinstance(info.context, dict) else None
        if not current_user:
            return None

        user_id = current_user.get("id")
        user_data = USERS_DB.get(user_id)
        if not user_data:
            return None

        return UserType(**user_data)

    @staticmethod
    def resolve_user(root, info, id):
        current_user = info.context.get("current_user") if isinstance(info.context, dict) else None
        if not current_user:
            return None

        # Only admins can look up other users
        requester = USERS_DB.get(current_user.get("id"))
        if not requester or not requester.get("is_admin"):
            return None

        user_data = USERS_DB.get(id)
        if not user_data:
            return None

        return UserType(**user_data)

    @staticmethod
    def resolve_all_users(root, info):
        current_user = info.context.get("current_user") if isinstance(info.context, dict) else None
        if not current_user:
            return []

        requester = USERS_DB.get(current_user.get("id"))
        if not requester or not requester.get("is_admin"):
            return []

        return [UserType(**data) for data in USERS_DB.values()]


class UserMutations(ObjectType):
    update_user_profile = UpdateUserProfile.Field()


schema = Schema(query=Query, mutation=UserMutations)


def execute_query(query_string, current_user=None):
    """Helper function to execute a GraphQL query with context."""
    context = {"current_user": current_user}
    result = schema.execute(query_string, context=context)
    if result.errors:
        print(f"Errors: {result.errors}")
    if result.data:
        print(f"Data: {result.data}")
    return result


